using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class GroupMembershipConfiguration : IEntityTypeConfiguration<GroupMembership>{public void Configure(EntityTypeBuilder<GroupMembership> builder){builder.ToTable("group_memberships");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("membership_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.Role).HasConversion<string>().HasMaxLength(20);builder.Property(e => e.Nickname).HasMaxLength(50);builder.HasOne(e => e.Group).WithMany(g => g.Memberships).HasForeignKey(e => e.GroupId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.User).WithMany(u => u.GroupMemberships).HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);builder.HasIndex(e => new { e.GroupId, e.UserId }).IsUnique();}}
